 +	if !state.currentInitContainerStart.IsZero() {
 +		initDuration := finishedAt.Sub(state.currentInitContainerStart)
 +		if initDuration > 0 {
 +			state.totalInitContainerRuntime += initDuration
 +		}
 +		state.currentInitContainerStart = time.Time{}
 +	}
